import './widgets/kpi-card.js';import './widgets/bar-chart-widget.js';import './widgets/line-chart-widget.js';import './widgets/area-chart-widget.js';import './widgets/pie-chart-widget.js';import './widgets/alerts-widget.js';import './widgets/activity-feed.js';import './widgets/data-table-widget.js';import './widgets/performance-gauge-widget.js';import './widgets/realtime-stats-widget.js';import './widgets/conversion-funnel.js';import './widgets/help-tour.js';import './widgets/command-palette.js';import './widgets/notification-bell.js';import{Logger}from './shared/logger.js';export{initializeWidgets,updateWidgetData,refreshWidget}from './widgets/index.js';function initializeDashboardWidgets(){Logger.log('[Dashboard Widgets] All widgets loaded');window.dispatchEvent(new CustomEvent('dashboard-widgets-ready'));if(typeof window.initializeWidgets==='function'){window.initializeWidgets();}}if(typeof document!=='undefined'){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initializeDashboardWidgets);}else{initializeDashboardWidgets();}}window.DashboardWidgets={updateKPI:(widgetId,data)=>{const widget=document.getElementById(widgetId);if(widget){if(data.value)widget.setAttribute('value',data.value);if(data.trend)widget.setAttribute('trend',data.trend);if(data.trendValue)widget.setAttribute('trend-value',data.trendValue);}},updateChart:(chartId,data)=>{const chart=document.getElementById(chartId);if(chart&&typeof chart.updateData==='function'){chart.updateData(data);}},showAlert:(options)=>{const alertsContainer=document.querySelector('.alerts-container');if(alertsContainer&&typeof alertsContainer.addAlert==='function'){alertsContainer.addAlert(options);}},refreshAll:()=>{window.dispatchEvent(new CustomEvent('dashboard-widgets-refresh'));}};Logger.log('[Dashboard Widgets] Bundle loaded');